const incoming = $input.all()[0].json;           // fetched RFP (rfp + screening)
const trigger = $input.all()[0].json.body ||      // original webhook body carried through n8n item chain
                ($('Webhook').item.json.body || {});
const rfp = incoming.rfp || {};
const screening = incoming.screening || {};
const kind = trigger.kind || 'info';

const sourceType = rfp.source_type || 'unknown';
const meta = rfp.source_metadata || {};
const sender = meta.from || meta.notice_id || meta.filename || meta.url || '';
const received = rfp.received_at ? new Date(rfp.received_at).toLocaleString() : '';
const breadcrumb = sourceType === 'email'
  ? `Source: email from ${sender} (received ${received})`
  : sourceType === 'sam_gov'
    ? `Source: SAM.gov notice ${meta.notice_id || rfp.external_id || ''} (received ${received})`
    : `Source: ${sourceType} ${sender} (received ${received})`;

const uiUrl = $env.KAIZEN_UI_URL || 'http://localhost:8501';
const reviewUrl = (kind === 'draft_ready' && trigger.draft_id)
  ? `${uiUrl}/?draft=${trigger.draft_id}`
  : `${uiUrl}/?rfp=${rfp.id}`;

const header = kind === 'draft_ready'
  ? `:memo: Draft ready — ${rfp.title || '(no title)'}`
  : `RFP: ${rfp.title || '(no title)'}`;

const fields = [
  { type: 'mrkdwn', text: `*Agency*\n${rfp.agency || '—'}` },
];
if (screening.fit_score !== undefined) {
  fields.push({ type: 'mrkdwn', text: `*Fit score*\n${screening.fit_score}` });
  fields.push({ type: 'mrkdwn', text: `*Recommendation*\n${screening.recommendation || '—'}` });
}

const payload = {
  text: header,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: header, emoji: true } },
    { type: 'section', fields },
    { type: 'context', elements: [{ type: 'mrkdwn', text: breadcrumb }] },
    { type: 'actions', elements: [
      { type: 'button', text: { type: 'plain_text', text: 'Review in dashboard' }, url: reviewUrl, style: 'primary' },
      { type: 'button', text: { type: 'plain_text', text: 'Dismiss' }, value: `dismiss_${rfp.id}` }
    ] }
  ]
};
return [{ json: payload }];
